var isBalanced = function(num) {
    let evenSum = 0;
    let oddSum = 0;
    for (let i = 0; i < num.length; i++) {
        const d = num.charCodeAt(i) - 48;
        if (i % 2 === 0) evenSum += d;
        else oddSum += d;
    }
    return evenSum === oddSum;
};
